mapper.select:
SELECT t.task_id, t.company_id, t.checklist_id, t.task_template_id, t.title, t.description, t.status, t.due_date, t.assigned_user_id, t.assigned_department_id, t.completed_at, t.created_by, t.created_at, t.updated_at, t.require_ack, t.require_doc, t.acknowledged_at, t.acknowledged_by, t.requires_manager_approval, t.approval_status, t.approved_by, t.approved_at, t.rejection_reason, t.approver_user_id, t.scheduled_start_at, t.scheduled_end_at, t.schedule_status, t.schedule_proposed_by, t.schedule_proposed_at, t.schedule_confirmed_by, t.schedule_confirmed_at, t.schedule_reschedule_reason, t.schedule_cancel_reason, t.schedule_no_show_reason FROM task_instances t INNER JOIN checklist_instances c ON t.checklist_id = c.checklist_id WHERE t.company_id = #{companyId} AND c.onboarding_id = #{onboardingId}
AND t.status = #{status}
AND t.assigned_user_id = #{assignedUserId}
ORDER BY t.due_date
ORDER BY t.status
ORDER BY t.created_at
DESC
ASC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM task_instances t
INNER JOIN checklist_instances c ON t.checklist_id = c.checklist_id
WHERE t.company_id = #{companyId}
  AND c.onboarding_id = #{onboardingId}

    AND t.status = #{status}


    AND t.assigned_user_id = #{assignedUserId}

mapper.delete:
DELETE FROM task_instances
WHERE company_id = #{companyId,jdbcType=VARCHAR}
  AND checklist_id = #{checklistId,jdbcType=VARCHAR}

mapper.select:
SELECT t.task_id, t.company_id, t.checklist_id, c.onboarding_id, c.name AS checklist_name, t.title, t.description, t.status, t.due_date, t.assigned_user_id, t.assigned_department_id, t.completed_at, t.created_at, t.require_ack, t.require_doc, t.requires_manager_approval, t.approval_status, t.approver_user_id, t.scheduled_start_at, t.scheduled_end_at, t.schedule_status, t.schedule_reschedule_reason, t.schedule_cancel_reason, t.schedule_no_show_reason FROM task_instances t INNER JOIN checklist_instances c ON t.checklist_id = c.checklist_id AND t.company_id = c.company_id WHERE t.company_id = #{companyId,jdbcType=VARCHAR} AND t.assigned_user_id = #{assigneeUserId,jdbcType=VARCHAR}
AND t.status = #{status}
ORDER BY t.due_date
ORDER BY t.status
ORDER BY t.created_at
DESC
ASC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM task_instances t
WHERE t.company_id = #{companyId,jdbcType=VARCHAR}
  AND t.assigned_user_id = #{assigneeUserId,jdbcType=VARCHAR}

    AND t.status = #{status}

SELECT t.task_id, t.company_id, t.checklist_id, c.onboarding_id, c.name AS checklist_name,
       t.title, t.description, t.status, t.due_date, t.assigned_user_id, t.assigned_department_id,
       t.completed_at, t.created_at, t.require_ack, t.require_doc, t.requires_manager_approval, t.approval_status, t.approver_user_id,
       t.scheduled_start_at, t.scheduled_end_at, t.schedule_status, t.schedule_reschedule_reason, t.schedule_cancel_reason,
       t.schedule_no_show_reason
FROM task_instances t
INNER JOIN checklist_instances c ON t.checklist_id = c.checklist_id AND t.company_id = c.company_id
WHERE t.company_id = #{companyId,jdbcType=VARCHAR}
  AND t.assigned_user_id = #{assigneeUserId,jdbcType=VARCHAR}
  AND t.scheduled_start_at IS NOT NULL

    AND t.scheduled_start_at  >=  #{fromTime,jdbcType=TIMESTAMP}


    AND t.scheduled_start_at  <=  #{toTime,jdbcType=TIMESTAMP}

ORDER BY t.scheduled_start_at ASC, t.created_at ASC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM task_instances t
WHERE t.company_id = #{companyId,jdbcType=VARCHAR}
  AND t.assigned_user_id = #{assigneeUserId,jdbcType=VARCHAR}
  AND t.scheduled_start_at IS NOT NULL

    AND t.scheduled_start_at  >=  #{fromTime,jdbcType=TIMESTAMP}


    AND t.scheduled_start_at  <=  #{toTime,jdbcType=TIMESTAMP}

SELECT t.task_id, t.company_id, t.checklist_id, c.onboarding_id, c.name AS checklist_name, t.title, t.description, t.status, t.due_date, t.assigned_user_id, t.assigned_department_id, t.completed_at, t.created_at, t.require_ack, t.require_doc, t.requires_manager_approval, t.approval_status, t.approver_user_id, t.scheduled_start_at, t.scheduled_end_at, t.schedule_status, t.schedule_reschedule_reason, t.schedule_cancel_reason, t.schedule_no_show_reason FROM task_instances t INNER JOIN checklist_instances c ON t.checklist_id = c.checklist_id AND t.company_id = c.company_id WHERE t.company_id = #{companyId,jdbcType=VARCHAR} AND c.onboarding_id = #{onboardingId,jdbcType=VARCHAR}
AND (t.status IS NULL OR UPPER(TRIM(t.status)) != 'DONE')
ORDER BY CASE WHEN t.assigned_user_id IS NULL OR TRIM(t.assigned_user_id) = '' THEN 1 ELSE 0 END ASC, t.assigned_user_id ASC, CASE WHEN t.due_date IS NULL THEN 1 ELSE 0 END ASC, t.due_date ASC, t.created_at ASC
